            vValue <- validateFilterValue(filter.value)
          } yield acc :+ Filter(vCol, vOp, vValue, vLogOp)
        case (left, _) => left
      }

      // Validate group by columns
      validGroupBy <- query.groupByColumns.foldLeft[Either[String, List[String]]](Right(List.empty)) {
