  /**
   * Validates an alias name to prevent injection through alias fields.
   */
  def validateAlias(alias: String): Either[String, String] = {
    val aliasPattern = "^[a-zA-Z_][a-zA-Z0-9_]{0,63}$".r
    if (aliasPattern.matches(alias)) Right(alias)
    else Left(s"Invalid alias '$alias'. Aliases must be alphanumeric with underscores, starting with a letter or underscore.")
  }

  /**
   * Validates filter values to ensure they are safe literal types.
   */
  def validateFilterValue(value: Any): Either[String, Any] = {
    value match {
      case _: Int | _: Long | _: Double | _: Float | _: Boolean => Right(value)
      case s: String =>
        // Ensure string values don't contain SQL injection patterns
        if (s.length > 1000) Left("Filter value too long (max 1000 characters)")
        else Right(s)
      case list: List[_] if list.forall(v => v.isInstanceOf[Int] || v.isInstanceOf[Long] || v.isInstanceOf[Double] || v.isInstanceOf[String]) =>
        Right(list)
      case _ => Left(s"Unsupported filter value type: ${value.getClass.getSimpleName}")
    }
  }

  /**
   * Escapes a string literal for safe use in Spark SQL.
   * Replaces single quotes with escaped single quotes.
   */
  def escapeStringLiteral(value: String): String = {
    value.replace("\\", "\\\\").replace("'", "\\'")
  }

  /**
   * Converts a filter value to a safe SQL literal representation.
   */
  def valueToSqlLiteral(value: Any): String = {
    value match {
      case s: String => s"'${escapeStringLiteral(s)}'"
      case i: Int => i.toString
      case l: Long => l.toString
      case d: Double => d.toString
      case f: Float => f.toString
      case b: Boolean => b.toString.toUpperCase
      case list: List[_] =>
        val literals = list.map(valueToSqlLiteral)
        s"(${literals.mkString(", ")})"
      case _ => throw new IllegalArgumentException(s"Unsupported value type: ${value.getClass}")
    }
  }

  /**
   * Builds a safe, parameterized SQL query from a validated AnalyticsQuery.
   * All identifiers are validated against allowlists, and all values are
   * properly escaped as literals.
   */
  def buildSafeQuery(query: AnalyticsQuery): String = {
    val sb = new StringBuilder("SELECT ")

    // Build SELECT clause from validated columns and aggregations
    val selectParts: List[String] = query.selectColumns.map { col =>
      if (col == "*") "*" else s"`$col`"
    } ++ query.aggregations.map { agg =>
      val colRef = if (agg.column == "*") "*" else s"`${agg.column}`"
      s"${agg.function}($colRef) AS `${agg.alias}`"
    }

    if (selectParts.isEmpty) {
      sb.append("*")
    } else {
      sb.append(selectParts.mkString(", "))
    }

    // FROM clause - table name is validated against allowlist
    sb.append(s" FROM `${query.table}`")

    // WHERE clause - columns validated, operators validated, values escaped
    if (query.filters.nonEmpty) {
      sb.append(" WHERE ")
      query.filters.zipWithIndex.foreach { case (filter, idx) =>
        if (idx > 0) {
          sb.append(s" ${filter.logicalOperator} ")
        }
        filter.operator.toUpperCase match {
          case "IS NULL" =>
            sb.append(s"`${filter.column}` IS NULL")
          case "IS NOT NULL" =>
            sb.append(s"`${filter.column}` IS NOT NULL")
          case "IN" =>
            val literal = valueToSqlLiteral(filter.value)
            sb.append(s"`${filter.column}` IN $literal")
          case "BETWEEN" =>
            filter.value match {
              case list: List[_] if list.size == 2 =>
                sb.append(s"`${filter.column}` BETWEEN ${valueToSqlLiteral(list.head)} AND ${valueToSqlLiteral(list(1))}")
              case _ =>
                throw new IllegalArgumentException("BETWEEN requires a list of exactly 2 values")
            }
          case op =>
            sb.append(s"`${filter.column}` $op ${valueToSqlLiteral(filter.value)}")
        }
      }
    }

    // GROUP BY clause - columns validated
    if (query.groupByColumns.nonEmpty) {
      sb.append(s" GROUP BY ${query.groupByColumns.map(c => s"`$c`").mkString(", ")}")
    }

    // ORDER BY clause - columns and directions validated
    if (query.orderByColumns.nonEmpty) {
      sb.append(s" ORDER BY ${query.orderByColumns.map(ob => s"`${ob.column}` ${ob.direction}").mkString(", ")}")
    }

    // LIMIT clause - validated as positive integer
    query.limit.foreach { l =>
      sb.append(s" LIMIT $l")
    }

    sb.toString()
  }

  /**
   * Executes a validated analytics query safely.
   */
  def executeQuery(query: AnalyticsQuery): QueryResult = {
