      case Left(error) =>
        QueryError(s"Validation error: $error")
      case Right(validatedQuery) =>
        Try {
          val sql = buildSafeQuery(validatedQuery)
          println(s"Executing safe query: $sql")
          val df = spark.sql(sql)
          val count = df.count()
          QuerySuccess(df, count)
        } match {
          case Success(result) => result
          case Failure(ex) => QueryError(s"Query execution error: ${ex.getMessage}")
        }
    }
  }

  /**
   * API handler that processes structured query requests.
   * This replaces direct SQL string execution with a safe, structured approach.
   */
  def handleAnalyticsRequest(requestBody: Map[String, Any]): QueryResult = {
    Try {
      val table = requestBody.getOrElse("table", "").toString
      val selectColumns = requestBody.getOrElse("select", List.empty).asInstanceOf[List[String]]
      val aggregations = requestBody.getOrElse("aggregations", List.empty).asInstanceOf[List[Map[String, String]]].map { aggMap =>
        Aggregation(
          function = aggMap.getOrElse("function", ""),
          column = aggMap.getOrElse("column", ""),
          alias = aggMap.getOrElse("alias", "")
        )
      }
      val filters = requestBody.getOrElse("filters", List.empty).asInstanceOf[List[Map[String, Any]]].map { filterMap =>
        Filter(
          column = filterMap.getOrElse("column", "").toString,
          operator = filterMap.getOrElse("operator", "=").toString,
          value = filterMap.getOrElse("value", ""),
          logicalOperator = filterMap.getOrElse("logical_operator", "AND").toString
        )
      }
      val groupByColumns = requestBody.getOrElse("group_by", List.empty).asInstanceOf[List[String]]
      val orderByColumns = requestBody.getOrElse("order_by", List.empty).asInstanceOf[List[Map[String, String]]].map { obMap =>
        OrderBy(
          column = obMap.getOrElse("column", ""),
          direction = obMap.getOrElse("direction", "ASC")
        )
      }
      val limit = requestBody.get("limit").map(_.asInstanceOf[Int])

      val query = AnalyticsQuery(
        table = table,
        selectColumns = selectColumns,
        aggregations = aggregations,
        filters = filters,
        groupByColumns = groupByColumns,
        orderByColumns = orderByColumns,
        limit = limit
      )

      executeQuery(query)
    } match {
      case Success(result) => result
      case Failure(ex) => QueryError(s"Request parsing error: ${ex.getMessage}")
    }
  }

